import { Component, OnInit } from '@angular/core';
import { SalesreportService } from './salesreport.service';
import { MatSnackBar } from '@angular/material/snack-bar';

@Component({
  selector: 'ux-salesreport',
  templateUrl: './salesreport.component.html',
  styleUrls: ['./salesreport.component.scss']
})
export class SalesreportComponent implements OnInit {
  from_date = '';
  to_date = '';
  report_data: any[] = [];
  grand_total = 0;
  grand_orders = 0;
  searched = false;

  constructor(
    private salesreportService: SalesreportService,
    private _snackBar: MatSnackBar
  ) {}

  ngOnInit() {}

  async onSearchClick() {
    if (this.from_date && this.to_date) {
      this.report_data = [];
      this.grand_total = 0;
      this.grand_orders = 0;
      this.searched = true;
      try {
        const res: any = await this.salesreportService.getUnitWiseReport({
          from_date: this.from_date,
          to_date: this.to_date
        });
        if (res.messagecode === 100) {
          this.report_data = res.report;
          this.report_data.forEach(row => {
            this.grand_total += Number(row.total || 0);
            this.grand_orders += Number(row.orders?.length || 0);
          });
        }
      } catch (err) {
        this._snackBar.open('Failed to fetch report', 'Error', { duration: 3000 });
      }
    } else {
      this._snackBar.open('Select From Date and To Date', 'Information', { duration: 3000 });
    }
  }
}
